typedef enum SDL_DisplayOrientation
{
 SDL_ORIENTATION_UNKNOWN, /**< تشير هذه القيمة إلى أن SDL لم تستطع تحديد اتجاه الشاشة الحالي، لذلك لا يجوز افتراض وضع عرض محدد من خلالها. */
 SDL_ORIENTATION_LANDSCAPE, /**< تشير هذه القيمة إلى أن SDL تصف الشاشة على أنها في الوضع الأفقي القياسي بالنسبة إلى الوضع العمودي المرجعي. */
 SDL_ORIENTATION_LANDSCAPE_FLIPPED, /**< تشير هذه القيمة إلى أن SDL تصف الشاشة على أنها في وضع أفقي مقلوب بالنسبة إلى الاتجاه المرجعي. */
 SDL_ORIENTATION_PORTRAIT, /**< تشير هذه القيمة إلى أن SDL تصف الشاشة على أنها في الوضع العمودي القياسي. */
 SDL_ORIENTATION_PORTRAIT_FLIPPED /**< تشير هذه القيمة إلى أن SDL تصف الشاشة على أنها في وضع عمودي مقلوب. */
} SDL_DisplayOrientation;
